import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import './BuyRequirements.css';

function BuyRequirements() {
  const [requirements, setRequirements] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    product_name: '',
    description: '',
    quantity: '',
    location: '',
    budget: ''
  });

  useEffect(() => {
    fetchRequirements();
  }, []);

  const fetchRequirements = async () => {
    try {
      const response = await axios.get('/api/buy-requirements');
      setRequirements(response.data);
    } catch (error) {
      console.error('Error fetching requirements:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        alert('Please login to post a buy requirement');
        return;
      }
      await axios.post('/api/buy-requirements', formData, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setShowForm(false);
      setFormData({ product_name: '', description: '', quantity: '', location: '', budget: '' });
      fetchRequirements();
      alert('Buy requirement posted successfully!');
    } catch (error) {
      console.error('Error posting requirement:', error);
      alert('Failed to post requirement');
    }
  };

  return (
    <div className="buy-requirements-page">
      <div className="container">
        <div className="page-header">
          <h1>Buy Requirements</h1>
          <p>Post your buying requirements and get quotes from verified suppliers</p>
          <button onClick={() => setShowForm(!showForm)} className="btn btn-primary">
            {showForm ? 'Cancel' : 'Post Buy Requirement'}
          </button>
        </div>

        {showForm && (
          <div className="requirement-form">
            <h3>Post Your Buy Requirement</h3>
            <form onSubmit={handleSubmit}>
              <div className="input-group">
                <label>Product Name *</label>
                <input
                  type="text"
                  required
                  value={formData.product_name}
                  onChange={(e) => setFormData({...formData, product_name: e.target.value})}
                  placeholder="What are you looking to buy?"
                />
              </div>
              <div className="input-group">
                <label>Description *</label>
                <textarea
                  required
                  value={formData.description}
                  onChange={(e) => setFormData({...formData, description: e.target.value})}
                  placeholder="Describe your requirements in detail..."
                />
              </div>
              <div className="form-row">
                <div className="input-group">
                  <label>Quantity</label>
                  <input
                    type="text"
                    value={formData.quantity}
                    onChange={(e) => setFormData({...formData, quantity: e.target.value})}
                    placeholder="e.g., 100 units"
                  />
                </div>
                <div className="input-group">
                  <label>Location</label>
                  <input
                    type="text"
                    value={formData.location}
                    onChange={(e) => setFormData({...formData, location: e.target.value})}
                    placeholder="e.g., Mumbai, India"
                  />
                </div>
              </div>
              <div className="input-group">
                <label>Budget</label>
                <input
                  type="text"
                  value={formData.budget}
                  onChange={(e) => setFormData({...formData, budget: e.target.value})}
                  placeholder="e.g., ₹50,000 - ₹1,00,000"
                />
              </div>
              <button type="submit" className="btn btn-primary">Post Requirement</button>
            </form>
          </div>
        )}

        {loading ? (
          <div className="loading">Loading requirements...</div>
        ) : (
          <div className="requirements-list">
            {requirements.length === 0 ? (
              <div className="no-results">
                <p>No buy requirements posted yet. Be the first to post one!</p>
              </div>
            ) : (
              requirements.map(req => (
                <div key={req.id} className="requirement-card">
                  <h3>{req.product_name}</h3>
                  <p className="requirement-description">{req.description}</p>
                  <div className="requirement-meta">
                    {req.quantity && <span>Quantity: {req.quantity}</span>}
                    {req.location && <span>Location: {req.location}</span>}
                    {req.budget && <span>Budget: {req.budget}</span>}
                    <span className="requirement-date">Posted: {new Date(req.created_at).toLocaleDateString()}</span>
                  </div>
                </div>
              ))
            )}
          </div>
        )}
      </div>
    </div>
  );
}

export default BuyRequirements;
